}

class Tetromino:
    def __init__(self, x, y, shape, color):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = color

    def rotate(self):
        # Rotate the shape 90 degrees clockwise
        rotated_shape = list(zip(*self.shape[::-1]))
        self.shape = [list(row) for row in rotated_shape]

    def move(self, dx):
        self.x += dx

    def move_down(self):
        self.y += 1


# Game grid dimensions
GRID_WIDTH = 10
GRID_HEIGHT = 20

# Initialize the game grid with None values
def create_grid(width, height):
    return [[None for _ in range(width)] for _ in range(height)]

# Example of initializing the grid
grid = create_grid(GRID_WIDTH, GRID_HEIGHT)


def is_valid_move(tetromino, grid):
    for row_index, row in enumerate(tetromino.shape):
        for col_index, cell in enumerate(row):
            if cell:
                x = tetromino.x + col_index
                y = tetromino.y + row_index

                if x < 0 or x >= GRID_WIDTH or y >= GRID_HEIGHT:
                    return False

                if y >= 0 and grid[y][x] is not None:
                    return False
    return True


def lock_tetromino(tetromino, grid):
    for row_index, row in enumerate(tetromino.shape):
        for col_index, cell in enumerate(row):
            if cell:
                x = tetromino.x + col_index
                y = tetromino.y + row_index
                if 0 <= y < GRID_HEIGHT and 0 <= x < GRID_WIDTH:
                    grid[y][x] = tetromino.color
